18.     return handleMap.has(k) && handleMap.get(k).endsWith('.dcf');
19. }
20. 
21. function fname(h) {
22.     const k = h.toString();
23.     if (!handleMap.has(k)) return '??';
24.     const f = handleMap.get(k);
25.     return f.split('\\').pop();
26. }
27. 
28. function hx(lo, hi) {
29.     if (!hi) return '0x' + lo.toString(16);
30.     return '0x' + ((hi * 0x100000000) + lo).toString(16);
31. }
32. 
33. function emit(api, h, d) {
