35.     const ds = Object.keys(d).map(k => k + '=' + d[k]).join(' ');
36.     console.log(String(seq).padStart(4) + ' ' + api.padEnd(20) + ' ' + fname(h).padEnd(25) + ' ' + ds);
37.     send({ seq, api, file: fname(h), handle: h.toString(), detail: d });
38. }
