49.         if ((ret.toInt32() >>> 0) === 0xFFFFFFFF || !this.fn || !this.fn.endsWith('.dcf')) return;
50.         handleMap.set(ret.toString(), this.fn);
51.         positionMap.set(ret.toString(), 0);
52.         var a = [];
53.         if (this.acc & 0x80000000) a.push('R');
54.         if (this.acc & 0x40000000) a.push('W');
