"""Parse sub-array stream in namespace serialization.

Each sub-array: [size_words:u64] [data: (sw-1)*8 bytes]
sw includes itself, so total block = sw*8 bytes.
Advance: pos += sw*8 (NOT (sw-1)*8).
TERM: sw=0, advance by 8.
"""
import struct, sys

def parse_dump_file(fn):
    dumps = {}
    cur, cb = None, []
    with open(fn, 'r', encoding='utf-8') as f:
        for line in f:
            l = line.strip()
            if l.startswith('DUMP '):
                cur = l.split()[1]; cb = []
            elif l == 'ENDDUMP':
                if cur: dumps[cur] = bytes(cb)
                cur = None
            elif cur is not None and l:
                try: cb.extend(int(x) for x in l.split())
                except ValueError: pass
    return dumps

def describe_subarray(data):
    """Describe a sub-array given its data (after size_words)."""
    if len(data) < 2:
        return '(short)'
    b0, b1 = data[0], data[1]
    # Name descriptors: 01 XX 00 88
    if len(data) >= 4 and data[0] == 1 and data[2] == 0 and data[3] == 0x88:
        typ = data[1]
        if typ == 0x28:
            ch = []
            for j in range(8, len(data), 2):
                if j+1 < len(data) and data[j] > 0 and data[j+1] == 0:
                    ch.append(chr(data[j]))
                else:
                    break
            return 'MEMBER_NAME "' + ''.join(ch) + '"'
        elif typ == 0x00:
            if len(data) > 8 and data[8] == 0xFF and data[9] == 0xFF:
                return 'NS_SELF_NAME (0xFFFF = anonymous)'
            nm = data[8:16].hex() if len(data) > 8 else '?'
            return f'NS_SELF_NAME ({nm})'
        elif typ == 0x35:
            ch = []
            for j in range(8, len(data), 2):
                if j+1 < len(data) and data[j] > 0 and data[j+1] == 0:
                    ch.append(chr(data[j]))
                else:
                    break
            return 'CHILD_NS_NAME "' + ''.join(ch) + '"'
        else:
            return f'DESC type=0x{typ:02x}'
    # Type codes
    nib = b0 & 0x0F
    rank = b0 >> 4
    types = {
        0x22: 'Int8', 0x25: 'Float64', 0x27: 'Char8', 0x28: 'Char16',
        0x29: 'Char32', 0x06: 'Nested', 0x21: 'Bool', 0x24: 'Int32',
        0x23: 'Int16', 0x2A: 'Complex128', 0x2E: 'Decimal128',
        0x14: 'Type0x14', 0x15: 'Type0x15'
    }
    if nib in (0x0F, 0x07) and b1 in types:
        tn = types[b1]
        kind = 'S' if nib == 0x0F else 'N'
        extra = ''
        if rank == 0:
            if b1 == 0x22 and len(data) > 8:
                extra = f'={data[8]}'
            elif b1 == 0x25 and len(data) > 15:
                extra = f'={struct.unpack_from("<d", data, 8)[0]}'
            elif b1 in (0x14, 0x15) and len(data) > 15:
                extra = f'=0x{data[8:16].hex()}'
        elif rank >= 1 and len(data) > 15:
            cnt = struct.unpack_from('<Q', data, 8)[0]
            extra = f'[{cnt}]'
            if b1 == 0x27 and cnt < 80 and len(data) > 16:
                extra += f'="{data[16:16+cnt].decode("ascii", "replace")}"'
            elif b1 == 0x22 and cnt < 30 and len(data) > 16:
                extra += f'={list(data[16:16+min(cnt,20)])}'
            elif b1 == 0x21:
                extra += f' bits=0x{data[16:min(16+8,len(data))].hex()}'
        return f'{tn} r{rank}{kind}{extra}'
    # Unknown
    return f'raw 0x{b0:02x}{b1:02x} ({len(data)}b) {data[:16].hex()}'


def parse_stream(P, start, max_items=60):
    """Parse stream of [sw:u64][data:(sw-1)*8 bytes] items. Advance by sw*8."""
    items = []
    pos = start
    for _ in range(max_items):
        if pos + 8 > len(P):
            break
        sw = struct.unpack_from('<Q', P, pos)[0]
        if sw == 0:
            items.append((pos, 0, 'TERM', b''))
            pos += 8
            continue
        data_len = (sw - 1) * 8
        end = pos + sw * 8  # advance includes the sw word itself
        if end > len(P) + 8:  # some tolerance
            items.append((pos, sw, f'(TRUNCATED sw={sw})', b''))
            break
        data = P[pos + 8:pos + 8 + data_len]
        desc = describe_subarray(data)
        items.append((pos, sw, desc, data))
        pos = end
    return items, pos


