                continue
            elif section == 'values':
                section = 'meta'
                print(f'  [{i:2d}] P+{pos:04x}: TERM')
                print('  ---- INTERNAL METADATA ----')
                continue

        print(f'  [{i:2d}] P+{pos:04x}: sw={sw:3d} {label:8s} {desc}')

    print(f'  stream ends at P+{end_pos:04x} ({end_pos}/{len(P)})')

